fun normalize(raw: String?): String =
    raw?.trim()
        ?.takeIf { it.length >= 3 }
        ?.lowercase()
        ?: "anonymous"

fun main() {
    println(normalize("  RiADH  "))
    println(normalize(" ab "))
    println(normalize(null))
}

fun load(ids: List<Long>): List<Row> =
    repository.fetch(ids)
        .apply { logger.info("fetched: {}", size) }
        .filter { it.isActive }
        .apply { logger.info("active: {}", this) }   // logs the LIST fine
        .map { it.normalize() }

